operations.command:
gh api graphql -f query='query { 
  __type(name: "CreateIssueInput") { 
    inputFields { 
      name 
      type { name kind ofType { name } } 
    } 
  } 
}' 2>/dev/null | jq '.data.__type.inputFields[] | select(.name | test("parent|sub|track"))' || echo "Query failed"

gh api graphql -f query='mutation { 
  __type: __schema { 
    mutationType { 
      fields { 
        name 
      } 
    } 
  } 
}' 2>/dev/null | jq '.data.__type.mutationType.fields[].name' | grep -i -E 'issue|sub|parent' | head -20 || echo "Query failed"
